description:
V případu https://app.aliteo.com/task/a08c41tgeg0bsg/?view=comments jsem přiložil cfg soubor licence, ten však nejde stáhnout.
K čemu mi ho tedy dovolilo přiložit? Hlavně na CFG není nic nebezpečného. Takové soubory si potřebujeme vyměňovat.


Mimochodem, už celkem dávno jsem dodával seznam textových souborů, které by mohly mít náhled, pokud jej ještě nemají a ten CFG náhled stále také nemá.

    public static readonly IReadOnlyCollection<string> TextFileExtensions = new HashSet<string>
    {
        // text a formátovaný text
        ".txt", ".text", ".txtile", ".log", ".md", ".properties", ".rst", ".tex", ".bib", ".ipynb",
        // data
        ".csv", ".tsv", ".xml", ".json", ".yaml", ".yml",
        // konfigurace
        ".ini", ".cfg", ".config", ".editorconfig", ".manifest", ".master", ".inf", ".env", ".toml", ".dockerfile",
        // šablony
        ".fdf", ".xfdf", ".xsl", ".xslt", ".xsd", ".dtd",
        // c# a Visual Studio
        ".cs", ".csproj", ".xaml", ".resx", ".wsdl", ".sln",
        ".c", ".h", ".cpp", ".hpp", ".vcproj", ".vb", ".vbproj",
        // skriptování a vývoj
        ".bat", ".cmd", ".vbs", ".ps1", ".psm1", ".psd1", ".sh", ".bash", ".zsh", ".reg",
        ".make", ".mk", ".gitignore", ".gitattributes", ".gitmodules",
        ".js", ".ts", ".css", ".less", ".scss", ".sass",
        ".htm", ".html", ".xhtml", ".mht", ".mhtml", ".svg",
        ".asp", ".ascx", ".aspx", ".jsp", ".php",
        ".sql", ".sqlplan", ".sqlproj", ".xdl",
        ".py", ".pyw", ".pl", ".pm", ".rb", ".gradle", ".groovy", ".lua",
        ".r", ".rmd", ".swift", ".go", ".java", ".kt", ".kts",
        // proprietární
        ".krd", ".kdc", ".mrt", ".srd",
    };
